/* Suggested markup: <div class="uiwiki-measured-pulse-control" tabindex="0"><span>Measured Pulse Control</span></div> */
.uiwiki-measured-pulse-control {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-measured-pulse-control > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #d8f34e;
  animation: measured_pulse_control 1.8s ease-in-out infinite alternate;
}
.uiwiki-measured-pulse-control:hover,
.uiwiki-measured-pulse-control:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes measured_pulse_control {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-measured-pulse-control, .uiwiki-measured-pulse-control > span { animation: none; transition: none; }
}
